import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Fabric 업데이트","description":"Fabric 업데이트 방법에 대한 단계적 설명서입니다.","frontmatter":{"title":"Fabric 업데이트","description":"Fabric 업데이트 방법에 대한 단계적 설명서입니다.","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"ko_kr/1.21.8/players/updating-fabric.md","filePath":"versions/1.21.8/translated/ko_kr/players/updating-fabric.md","lastUpdated":1760721669000}`);var c={name:`ko_kr/1.21.8/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Fabric 업데이트 <a class="header-anchor" href="#h1" aria-label="Permalink to “Fabric 업데이트”">​</a></h1><p>이 설명서는 Minecraft Launcher의 Fabric을 업데이트하는 방법에 대해 단계적으로 설명합니다.</p><p>제3자 런처의 경우, 해당 런처의 문서를 참조하여 주세요.</p><p>Fabric을 업데이트하는 것은 Fabric을 설치하는 것과 거의 같기 때문에, 이 설명서의 일부는 <a href="./installing-fabric">Fabric 설치</a>와 같은 내용일 수 있습니다.</p><h2 id="why-should-i-update-fabric-loader" tabindex="-1">왜 Fabric 로더를 업데이트해야 하나요? <a class="header-anchor" href="#why-should-i-update-fabric-loader" aria-label="Permalink to “왜 Fabric 로더를 업데이트해야 하나요?”">​</a></h2><p>최신 모드는 최신 Fabric 로더가 필요할 수 있으므로, 최신 모드를 사용하려면 Fabric 로더를 항상 최신으로 유지해야 합니다.</p><p>이 가이드는 오직 공식 Minecraft 런처용 Fabric 설치 방법을 안내합니다. 제3자 런처의 경우, 해당 런처의 문서를 참조하여 주세요.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Fabric 설치기 다운로드 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Fabric 설치기 다운로드”">​</a></h2><p><a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 웹사이트</a>에서 Fabric 설치기를 다운로드할 수 있습니다.</p><p>Windows를 사용한다면, Java 설치를 건너뛸 수 있도록 <code>exe</code> 버전 (<code>Windows 용 다운로드</code>) 을 다운로드하세요. 자동으로 공식 런처와 함께 제공되는 Java를 사용합니다.</p><p>macOS 또는 Linux 둥 UNIX 계열의 운영 체제를 사용한다면, <code>.jar</code> 버전을 다운로드 받아야 합니다. 때로는, 다음 단계로 이동하기 전에 Java를 설치해야 할 수도 있습니다.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Fabric 설치기 시작 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Fabric 설치기 시작”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>설치기를 시작하기 전에, 먼저 모든 Minecraft 인스턴스와 Minecrft 런처를 종료해야 합니다.</p></div><details class="details custom-block"><summary>macOS 사용자들을 위한 정보</summary><p>macOS는, 다운로드 디렉터리에서 <code>.jar</code> 파일을 마우스 오른쪽 버튼으로 클릭하고 <code>열기</code>를 클릭하여 실행해야 할 수 있습니다.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Fabric 실행기의 MacOS 컨텍스트 메뉴" loading="lazy"></p><p>정말로 실행할 것인지 묻는다면, 다시 한번 <code>열기</code>를 클릭해주세요.</p></details><p>설치기를 실행하면, 다음과 같은 화면이 나타날 것입니다:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="&quot;Install&quot;을 강조 표시한 Fabric 설치기" loading="lazy"></p><p>Fabric을 업데이트 하려면, 간단히 Fabric 설치기에서 Minecraft 버전이 올바르게 선택되어 있는지 확인하고 <code>설치</code>를 클릭하면 됩니다.</p><div class="warning custom-block"><p class="custom-block-title">중요!</p><p><code>프로필 생성</code>을 선택 &quot;해제&quot; 했는지 확인하세요. 그렇지 않으면 필요하지 않은 새로운 프로필이 생성될 수 있습니다.</p></div><h2 id="3-open-the-profile-in-the-minecraft-launcher" tabindex="-1">3. Minecraft 런처에서 프로필 열기 <a class="header-anchor" href="#3-open-the-profile-in-the-minecraft-launcher" aria-label="Permalink to “3. Minecraft 런처에서 프로필 열기”">​</a></h2><p>설치기가 업데이트를 완료했다면, Minecraft 런처를 실행하여 <code>설치 설정</code> 탭을 선택합니다. 그런 다음 Fabric 프로필의 수정 화면으로 이동합니다.</p><p>버전을 방금 설치한 Fabric 로더로 선택한 다음, <code>저장</code>을 클릭합니다.</p><p><img src="/assets/players/updating-fabric.png" alt="Minecraft 런처에서 Fabric 로더 버전을 변경하는 모습" loading="lazy"></p><h2 id="4-you-re-done" tabindex="-1">4. 이제 끝났습니다! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. 이제 끝났습니다!”">​</a></h2><p>위의 과정을 모두 완료했다면 <code>플레이</code> 탭으로 돌아가서, 왼쪽 아래의 버전 선택 메뉴에서 Fabric을 선택한 다음 플레이를 클릭하면 됩니다.</p><p>설치 과정 중 문제가 발생했다면, <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord (영어)</a>의 <code>#player-support</code> 채널에서 도움을 요청할 수 있습니다.</p>`,25)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};